import React from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { showDevNav } from '../../dev/isStandalone';
import styles from './SimpleNotFoundPage.module.css';

/** MFE-local 404 — không dùng common-components NotFoundPage (cần root `auth` slice). */
export const SimpleNotFoundPage: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const home = showDevNav ? '/dev' : '/dashboard';

  return (
    <div className={styles.wrap}>
      <h1 className={styles.code}>404</h1>
      <p>
        Trang <code>{location.pathname}</code> không tồn tại.
      </p>
      <div className={styles.actions}>
        <button type="button" className={styles.button} onClick={() => navigate(home, { replace: true })}>
          Về trang chủ
        </button>
        <button type="button" className={styles.button} onClick={() => navigate(-1)}>
          Quay lại
        </button>
        {showDevNav && (
          <Link to="/dev" className={styles.link}>Dev Navigation</Link>
        )}
      </div>
    </div>
  );
};
