import React from 'react';
import { MemoryRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Provider } from 'react-redux';
import { store } from './store/store';
import { AppLayout } from './components/layout/AppLayout';
import { SimpleNotFoundPage } from './components/layout/SimpleNotFoundPage';
import { isStandalone, showDevNav } from './dev/isStandalone';
import { StandaloneMockNav } from './standalone/StandaloneMockNav';
import { MemoryRouterSync } from './router/MemoryRouterSync';
import { getBrowserRouterPath } from './routing/routerPaths';
import type { IRootProps } from './types/IRootProps';
import pageSuspenseStyles from './components/layout/PageSuspense.module.css';

const DevPage = React.lazy(() => import('./dev/DevPage'));

// ── Dashboard ──────────────────────────────────────────────────────────────
const DashboardPage = React.lazy(() => import('./pages/dashboard/DashboardPage'));

// ── Báo Cáo (baocao) ─────────────────────────────────────────────────────
const BaoCaoBanHangPage      = React.lazy(() => import('./pages/baocao/BaoCaoBanHangPage'));
const BaoCaoMuaHangPage      = React.lazy(() => import('./pages/baocao/BaoCaoMuaHangPage'));
const BaoCaoCongNoPage       = React.lazy(() => import('./pages/baocao/BaoCaoCongNoPage'));
const BaoCaoNxtPage          = React.lazy(() => import('./pages/baocao/BaoCaoNxtPage'));
const BaoCaoTonKhoCuPage     = React.lazy(() => import('./pages/baocao/BaoCaoTonKhoCuPage'));
const BaoCaoDoanhThuPage     = React.lazy(() => import('./pages/baocao/BaoCaoDoanhThuPage'));
const BaoCaoChiPhiPage       = React.lazy(() => import('./pages/baocao/BaoCaoChiPhiPage'));
const BaoCaoTaiChinhPage     = React.lazy(() => import('./pages/baocao/BaoCaoTaiChinhPage'));
const BaoCaoLuongPage        = React.lazy(() => import('./pages/baocao/BaoCaoLuongPage'));
const BaoCaoTscdPage         = React.lazy(() => import('./pages/baocao/BaoCaoTscdPage'));
const BaoCaoCcdcPage         = React.lazy(() => import('./pages/baocao/BaoCaoCcdcPage'));
const BaoCaoSpLoiPage        = React.lazy(() => import('./pages/baocao/BaoCaoSpLoiPage'));
const BangKeVatMuaPage       = React.lazy(() => import('./pages/baocao/BangKeVatMuaPage'));
const BangKeVatBanPage       = React.lazy(() => import('./pages/baocao/BangKeVatBanPage'));
const NhatKyChungTuPage      = React.lazy(() => import('./pages/baocao/NhatKyChungTuPage'));
const SoCaiPage              = React.lazy(() => import('./pages/baocao/SoCaiPage'));
const PhanTichPage           = React.lazy(() => import('./pages/baocao/PhanTichPage'));
const TongHopImportDuLieuPage = React.lazy(() => import('./pages/baocao/TongHopImportDuLieuPage'));
const B01DnPage              = React.lazy(() => import('./pages/baocao/B01DnPage'));
const B02DnPage              = React.lazy(() => import('./pages/baocao/B02DnPage'));
const B03DnPage              = React.lazy(() => import('./pages/baocao/B03DnPage'));

const PageSuspense = ({ children }: { children: React.ReactNode }) => (
  <React.Suspense fallback={<div className={pageSuspenseStyles.fallback}>Đang tải...</div>}>
    {children}
  </React.Suspense>
);

const AppShell = () => (
  <>
    {isStandalone && <StandaloneMockNav />}
    <AppLayout />
  </>
);

const Root: React.FC<Partial<IRootProps>> = (_rootProps = {}) => (
  <Provider store={store}>
    <MemoryRouter
      initialEntries={[getBrowserRouterPath()]}
      future={{ v7_startTransition: true, v7_relativeSplatPath: true }}
    >
      <MemoryRouterSync />
      <Routes>
          <Route path="/" element={isStandalone ? <AppShell /> : <AppLayout />}>
            {showDevNav && (
              <>
                <Route index element={<Navigate to="/dev" replace />} />
                <Route path="dev" element={<PageSuspense><DevPage /></PageSuspense>} />
              </>
            )}
            <Route path="dashboard" element={<PageSuspense><DashboardPage /></PageSuspense>} />

            <Route path="baocao" element={<Navigate to="baocao/ban-hang" replace />} />
            <Route path="baocao/ban-hang"       element={<PageSuspense><BaoCaoBanHangPage /></PageSuspense>} />
            <Route path="baocao/mua-hang"       element={<PageSuspense><BaoCaoMuaHangPage /></PageSuspense>} />
            <Route path="baocao/cong-no"        element={<PageSuspense><BaoCaoCongNoPage /></PageSuspense>} />
            <Route path="baocao/nxt"            element={<PageSuspense><BaoCaoNxtPage /></PageSuspense>} />
            <Route path="baocao/ton-kho-cu"     element={<PageSuspense><BaoCaoTonKhoCuPage /></PageSuspense>} />
            <Route path="baocao/doanh-thu"      element={<PageSuspense><BaoCaoDoanhThuPage /></PageSuspense>} />
            <Route path="baocao/chi-phi"        element={<PageSuspense><BaoCaoChiPhiPage /></PageSuspense>} />
            <Route path="baocao/tai-chinh"      element={<PageSuspense><BaoCaoTaiChinhPage /></PageSuspense>} />
            <Route path="baocao/luong"          element={<PageSuspense><BaoCaoLuongPage /></PageSuspense>} />
            <Route path="baocao/tscd"           element={<PageSuspense><BaoCaoTscdPage /></PageSuspense>} />
            <Route path="baocao/ccdc"           element={<PageSuspense><BaoCaoCcdcPage /></PageSuspense>} />
            <Route path="baocao/sp-loi"         element={<PageSuspense><BaoCaoSpLoiPage /></PageSuspense>} />
            <Route path="baocao/bang-ke-vat-mua" element={<PageSuspense><BangKeVatMuaPage /></PageSuspense>} />
            <Route path="baocao/bang-ke-vat-ban" element={<PageSuspense><BangKeVatBanPage /></PageSuspense>} />
            <Route path="baocao/nhat-ky-chung-tu" element={<PageSuspense><NhatKyChungTuPage /></PageSuspense>} />
            <Route path="baocao/so-cai"         element={<PageSuspense><SoCaiPage /></PageSuspense>} />
            <Route path="baocao/phan-tich"      element={<PageSuspense><PhanTichPage /></PageSuspense>} />
            <Route path="baocao/tong-hop-import" element={<PageSuspense><TongHopImportDuLieuPage /></PageSuspense>} />
            <Route path="baocao/b01-dn"         element={<PageSuspense><B01DnPage /></PageSuspense>} />
            <Route path="baocao/b02-dn"         element={<PageSuspense><B02DnPage /></PageSuspense>} />
            <Route path="baocao/b03-dn"         element={<PageSuspense><B03DnPage /></PageSuspense>} />

            <Route path="*" element={<SimpleNotFoundPage />} />
          </Route>
      </Routes>
    </MemoryRouter>
  </Provider>
);

export default Root;
